"""Экран загрузки: первое, что отображается при запуске GUI."""from __future__ import annotationsimport tkinter as tkfrom dataclasses import replacefrom tkinter import ttkfrom typing import Callablefrom src.core import AVAILABLE_LANGUAGES, AppConfigStore, language_choice_required, set_languagefrom src.core.app_path import resolve_runtime_rootfrom src.gui.screens.base_screen import BaseGUIScreenfrom src.gui.template.styles import PALETTEfrom src.gui.template.styles.theme import SPACINGfrom src.gui.utils.tk_scaled_image import (    label_with_photoimage,    load_scaled_photoimage,    resolve_logo_asset_path,)# Длинная сторона растра логотипа (логические единицы Tk; с учётом tk scaling в load_scaled_photoimage)._LOADER_LOGO_MAX_SIDE_PT = 360class LoadingScreen(BaseGUIScreen):    """Экран загрузки при старте приложения."""    SCREEN_CODE = "loading"    SCREEN_TITLE = "unidoc2md"    def __init__(        self,        parent: ttk.Frame,        *,        on_language_ready: Callable[[], None] | None = None,        **kwargs: object,    ) -> None:        self._on_language_ready = on_language_ready        super().__init__(parent, **kwargs)        self._logo_photo: tk.PhotoImage | None = None        self._build_ui()    def _persist_language(self, code: str) -> None:        """Пишет [CORE] LANGUAGE в app.ini и синхронизирует AppConfigStore (см. AppConfigStore.save)."""        root = self._app_root if self._app_root is not None else resolve_runtime_root()        cfg = AppConfigStore.get()        new_core = replace(cfg.core, language=code)        new_cfg = replace(cfg, core=new_core)        AppConfigStore.save(new_cfg, root)    def _on_language_chosen(self, code: str) -> None:        """Активирует каталог перевода, затем фиксирует язык в AppConfigStore и app.ini."""        set_language(code)        self._persist_language(code)        self._notify_locale_changed()        if self._on_language_ready is not None:            self._on_language_ready()    def _notify_locale_changed(self) -> None:        """Как после сохранения настроек: обновить подписи на уже созданных экранах."""        try:            from src.gui.gui_controller import GUIController            GUIController.get().notify_locale_changed()        except Exception:            pass    def _build_ui(self) -> None:        bg = PALETTE["bg_main"]        outer = tk.Frame(self, bg=bg, highlightthickness=0, bd=0)        outer.pack(fill=tk.BOTH, expand=True)        inner = tk.Frame(outer, bg=bg, bd=0, highlightthickness=0)        inner.place(relx=0.5, rely=0.5, anchor=tk.CENTER)        path = resolve_logo_asset_path()        if path is not None:            self._logo_photo = load_scaled_photoimage(                path, outer, _LOADER_LOGO_MAX_SIDE_PT            )            if self._logo_photo is not None:                label_with_photoimage(                    inner,                    self._logo_photo,                    bg=bg,                    bd=0,                    highlightthickness=0,                ).pack(pady=(0, 0))        if not language_choice_required():            return        row = ttk.Frame(inner)        _pad_y = SPACING["md"]        row.pack(pady=(_pad_y, _pad_y))        _gap = SPACING["sm"] // 2        for code, label in AVAILABLE_LANGUAGES.items():            ttk.Button(                row,                text=label,                style="Secondary.TButton",                command=lambda c=code: self._on_language_chosen(c),            ).pack(side=tk.LEFT, padx=(_gap, _gap))